class Solution {
    public int[] popcountDepth(long[] nums, long[][] queries) {
        int[] depthCount = new int[nums.length];
        for (int i = 0; i < nums.length; i++) {
            depthCount[i] = getPopcountDepth(nums[i]);
        }

        int[] answers = new int[queries.length];
        int j = 0;
        for (long[] query : queries) {
            if (query[0] == 1) {
                int count = 0;
                for (int i = (int) query[1]; i <= query[2]; i++) {
                    if (depthCount[i] == query[3]) {
                        count++;
                    }
                }
                answers[j++] = count;
            } else {
                int idx = (int) query[1];
                long val = query[2];
                depthCount[idx] = getPopcountDepth(val);
            }
        }
        return answers;
    }

    private int getPopcountDepth(long x) {
        int depth = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            depth++;
        }
        return depth;
    }
}
